const SCRIPT_CONTENT = {
  "01_user_group_setup.sh": "#!/usr/bin/env bash\n# Smart Port Billing Infrastructure \u2014 User & Group Provisioning\n# RHCSA Skills: User/Group Management, Password Policy, Sudo Configuration\n# Run as root on RHEL 9\nset -euo pipefail\ntrap 'echo \"[ERROR] Line ${LINENO}: ${BASH_COMMAND}\" >&2; exit 1' ERR\n\n# \u2500\u2500 Colours \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nRED='\\033[0;31m'; GREEN='\\033[0;32m'; CYAN='\\033[0;36m'\nYELLOW='\\033[1;33m'; BOLD='\\033[1m'; RESET='\\033[0m'\n\nlog()  { echo -e \"${CYAN}[$(date '+%H:%M:%S')] INFO${RESET}  $*\"; }\nok()   { echo -e \"${GREEN}[$(date '+%H:%M:%S')]  OK  ${RESET}  $*\"; }\nwarn() { echo -e \"${YELLOW}[$(date '+%H:%M:%S')] WARN${RESET}  $*\"; }\ndie()  { echo -e \"${RED}[$(date '+%H:%M:%S')] FAIL${RESET}  $*\" >&2; exit 1; }\n\n# \u2500\u2500 Pre-flight \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n[[ $EUID -ne 0 ]] && die \"Must be run as root.\"\nlog \"Starting Port Billing user provisioning...\"\n\n# \u2500\u2500 Department Groups \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndeclare -A GROUPS=(\n    [billing-admin]=\"Port Billing Administrators\"\n    [billing-ops]=\"Billing Operations Team\"\n    [port-ops]=\"Port Operations Team\"\n    [billing-readonly]=\"Billing Read-Only Auditors\"\n)\n\nfor grp in \"${!GROUPS[@]}\"; do\n    if getent group \"$grp\" &>/dev/null; then\n        warn \"Group '$grp' already exists \u2014 skipping\"\n    else\n        groupadd --system \"$grp\"\n        ok \"Created group: $grp (${GROUPS[$grp]})\"\n    fi\ndone\n\n# \u2500\u2500 Department Users \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Format: username:group:comment\ndeclare -a USERS=(\n    \"portadmin:billing-admin:Port Billing System Administrator\"\n    \"billmgr:billing-ops:Billing Operations Manager\"\n    \"portclerk:billing-ops:Port Billing Clerk\"\n    \"opswatch:port-ops:Port Operations Watch Officer\"\n    \"auditor:billing-readonly:Billing Compliance Auditor\"\n)\n\nfor entry in \"${USERS[@]}\"; do\n    IFS=':' read -r uname ugroup ucomment <<< \"$entry\"\n    if id \"$uname\" &>/dev/null; then\n        warn \"User '$uname' already exists \u2014 skipping\"\n        continue\n    fi\n    useradd \\\n        --gid \"$ugroup\" \\\n        --groups \"$ugroup\" \\\n        --comment \"$ucomment\" \\\n        --create-home \\\n        --shell /bin/bash \\\n        --password \"$(openssl passwd -6 'ChangeMe@2024!')\" \\\n        \"$uname\"\n    # Force password change on first login\n    chage --lastday 0 \"$uname\"\n    ok \"Created user: $uname \u2192 group: $ugroup\"\ndone\n\n# \u2500\u2500 Password Policy \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Apply to all billing department users\nfor entry in \"${USERS[@]}\"; do\n    uname=\"${entry%%:*}\"\n    chage \\\n        --maxdays   90 \\\n        --mindays    7 \\\n        --warndays  14 \\\n        --inactive  30 \\\n        \"$uname\"\n    ok \"Password policy applied: $uname\"\ndone\n\n# \u2500\u2500 Sudo Configuration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nSUDOERS_FILE=\"/etc/sudoers.d/portbill-billing-admin\"\ncat > \"$SUDOERS_FILE\" <<'EOF'\n# Port Billing \u2014 billing-admin sudo rules\n# Allow billing admins to manage portbill service and billing directories\n%billing-admin ALL=(ALL) /usr/bin/systemctl start portbill\n%billing-admin ALL=(ALL) /usr/bin/systemctl stop portbill\n%billing-admin ALL=(ALL) /usr/bin/systemctl restart portbill\n%billing-admin ALL=(ALL) /usr/bin/systemctl status portbill\n%billing-admin ALL=(ALL) /usr/sbin/useradd, /usr/sbin/usermod, /usr/sbin/userdel\n%billing-admin ALL=(ALL) /usr/bin/journalctl -u portbill\n%billing-readonly ALL=(ALL) NOPASSWD: /usr/bin/journalctl -u portbill --no-pager\nEOF\nchmod 0440 \"$SUDOERS_FILE\"\nvisudo -c -f \"$SUDOERS_FILE\" || die \"sudoers syntax error \u2014 aborting\"\nok \"Sudo rules written: $SUDOERS_FILE\"\n\n# \u2500\u2500 Home Directory Permissions \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfor entry in \"${USERS[@]}\"; do\n    uname=\"${entry%%:*}\"\n    home=\"/home/$uname\"\n    [[ -d \"$home\" ]] || continue\n    chmod 0750 \"$home\"\n    ok \"Secured home: $home (0750)\"\ndone\n\n# \u2500\u2500 Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\necho -e \"\\n${BOLD}${CYAN}\u2554\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2557${RESET}\"\necho -e \"${BOLD}${CYAN}\u2551   User Provisioning Complete              \u2551${RESET}\"\necho -e \"${BOLD}${CYAN}\u255a\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u255d${RESET}\"\necho -e \"  Groups created  : ${#GROUPS[@]}\"\necho -e \"  Users created   : ${#USERS[@]}\"\necho -e \"  Sudo config     : $SUDOERS_FILE\"\necho -e \"  Default password: ChangeMe@2024! (forced change on login)\"\necho \"\"\n",

  "02_storage_lvm.sh": "#!/usr/bin/env bash\n# Smart Port Billing Infrastructure \u2014 LVM Storage Provisioning\n# RHCSA Skills: LVM (PV/VG/LV), XFS Filesystem, Persistent fstab Mounts\n# Run as root on RHEL 9 \u2014 Requires unformatted block device (default: /dev/sdb)\nset -euo pipefail\ntrap 'echo \"[ERROR] Line ${LINENO}: ${BASH_COMMAND}\" >&2; exit 1' ERR\n\nRED='\\033[0;31m'; GREEN='\\033[0;32m'; CYAN='\\033[0;36m'\nYELLOW='\\033[1;33m'; BOLD='\\033[1m'; RESET='\\033[0m'\n\nlog()  { echo -e \"${CYAN}[$(date '+%H:%M:%S')] INFO${RESET}  $*\"; }\nok()   { echo -e \"${GREEN}[$(date '+%H:%M:%S')]  OK  ${RESET}  $*\"; }\nwarn() { echo -e \"${YELLOW}[$(date '+%H:%M:%S')] WARN${RESET}  $*\"; }\ndie()  { echo -e \"${RED}[$(date '+%H:%M:%S')] FAIL${RESET}  $*\" >&2; exit 1; }\n\n# \u2500\u2500 Configuration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nBLOCK_DEVICE=\"${1:-/dev/sdb}\"          # Override: ./02_storage_lvm.sh /dev/sdc\nVG_NAME=\"portbill-vg\"\ndeclare -A LV_CONFIG=(\n    [billing-data]=\"10G:/srv/portbill/data:Billing transaction records\"\n    [billing-logs]=\"5G:/srv/portbill/logs:Application and audit logs\"\n    [billing-backup]=\"15G:/srv/portbill/backup:Automated backup target\"\n)\n\n# \u2500\u2500 Pre-flight \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n[[ $EUID -ne 0 ]]            && die \"Must be run as root.\"\ncommand -v pvcreate &>/dev/null || die \"lvm2 not installed: dnf install -y lvm2\"\n[[ -b \"$BLOCK_DEVICE\" ]]     || die \"Block device not found: $BLOCK_DEVICE\"\n\nlog \"Target device: $BLOCK_DEVICE\"\nlsblk \"$BLOCK_DEVICE\"\n\n# Safety check \u2014 refuse to wipe a mounted or used device\nif grep -q \"$BLOCK_DEVICE\" /proc/mounts 2>/dev/null; then\n    die \"$BLOCK_DEVICE is currently mounted. Aborting to prevent data loss.\"\nfi\nif pvs \"$BLOCK_DEVICE\" &>/dev/null; then\n    warn \"$BLOCK_DEVICE already a PV \u2014 skipping pvcreate\"\nelse\n    read -rp \"WARNING: This will wipe $BLOCK_DEVICE. Continue? [yes/N] \" confirm\n    [[ \"$confirm\" == \"yes\" ]] || die \"Aborted by user.\"\n    pvcreate --force \"$BLOCK_DEVICE\"\n    ok \"Physical Volume created: $BLOCK_DEVICE\"\nfi\n\n# \u2500\u2500 Volume Group \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif vgs \"$VG_NAME\" &>/dev/null; then\n    warn \"VG '$VG_NAME' already exists \u2014 skipping vgcreate\"\nelse\n    vgcreate \"$VG_NAME\" \"$BLOCK_DEVICE\"\n    ok \"Volume Group created: $VG_NAME\"\nfi\n\n# \u2500\u2500 Logical Volumes, XFS, fstab \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfor lv_name in \"${!LV_CONFIG[@]}\"; do\n    IFS=':' read -r lv_size mount_point lv_desc <<< \"${LV_CONFIG[$lv_name]}\"\n    lv_path=\"/dev/$VG_NAME/$lv_name\"\n\n    if lvs \"$lv_path\" &>/dev/null; then\n        warn \"LV '$lv_name' already exists \u2014 skipping\"\n    else\n        lvcreate --name \"$lv_name\" --size \"$lv_size\" \"$VG_NAME\"\n        ok \"Logical Volume created: $lv_name ($lv_size)\"\n        mkfs.xfs -L \"$lv_name\" \"$lv_path\"\n        ok \"XFS filesystem created: $lv_path\"\n    fi\n\n    # Create mount point\n    mkdir -p \"$mount_point\"\n    chown root:billing-ops \"$mount_point\"\n    chmod 2775 \"$mount_point\"\n\n    # Idempotent fstab entry (keyed on mount point)\n    lv_uuid=$(blkid -s UUID -o value \"$lv_path\")\n    fstab_entry=\"UUID=$lv_uuid  $mount_point  xfs  defaults,noatime,_netdev  0 2\"\n    if grep -q \"UUID=$lv_uuid\" /etc/fstab; then\n        warn \"fstab entry for $lv_name already exists \u2014 skipping\"\n    else\n        echo \"$fstab_entry\" >> /etc/fstab\n        ok \"fstab entry added: $mount_point\"\n    fi\n\n    # Mount if not already mounted\n    if mountpoint -q \"$mount_point\"; then\n        warn \"$mount_point already mounted \u2014 skipping\"\n    else\n        mount \"$mount_point\"\n        ok \"Mounted: $mount_point\"\n    fi\n    log \"  $lv_name \u2192 $mount_point ($lv_desc)\"\ndone\n\n# \u2500\u2500 SELinux Contexts \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nsemanage fcontext --add --type httpd_sys_content_t \"/srv/portbill/data(/.*)?\" 2>/dev/null || \\\n    warn \"SELinux fcontext may already exist for data dir\"\nsemanage fcontext --add --type var_log_t \"/srv/portbill/logs(/.*)?\" 2>/dev/null || \\\n    warn \"SELinux fcontext may already exist for logs dir\"\nrestorecon -Rv /srv/portbill/\nok \"SELinux contexts applied to /srv/portbill/\"\n\n# \u2500\u2500 Verification \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\necho -e \"\\n${BOLD}${CYAN}\u2500\u2500 LVM Storage Layout \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500${RESET}\"\npvs  --noheadings -o pv_name,vg_name,pv_size,pv_free \"$BLOCK_DEVICE\"\nvgs  --noheadings -o vg_name,lv_count,vg_size,vg_free \"$VG_NAME\"\nlvs  --noheadings -o lv_name,lv_size,lv_path \"$VG_NAME\"\necho \"\"\ndf -hT /srv/portbill/data /srv/portbill/logs /srv/portbill/backup\necho \"\"\nok \"Storage provisioning complete.\"\n",

  "03_firewall_selinux.sh": "#!/usr/bin/env bash\n# Smart Port Billing Infrastructure \u2014 Firewall & SELinux Hardening\n# RHCSA Skills: firewalld Zone Management, Rich Rules, SELinux Contexts & Booleans\n# Run as root on RHEL 9\nset -euo pipefail\ntrap 'echo \"[ERROR] Line ${LINENO}: ${BASH_COMMAND}\" >&2; exit 1' ERR\n\nRED='\\033[0;31m'; GREEN='\\033[0;32m'; CYAN='\\033[0;36m'\nYELLOW='\\033[1;33m'; BOLD='\\033[1m'; RESET='\\033[0m'\n\nlog()  { echo -e \"${CYAN}[$(date '+%H:%M:%S')] INFO${RESET}  $*\"; }\nok()   { echo -e \"${GREEN}[$(date '+%H:%M:%S')]  OK  ${RESET}  $*\"; }\nwarn() { echo -e \"${YELLOW}[$(date '+%H:%M:%S')] WARN${RESET}  $*\"; }\ndie()  { echo -e \"${RED}[$(date '+%H:%M:%S')] FAIL${RESET}  $*\" >&2; exit 1; }\n\n# \u2500\u2500 Configuration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nSSH_PORT=2222\nBILLING_ZONE=\"portbilling\"\nTRUSTED_ADMIN_CIDR=\"192.168.10.0/24\"   # Admin workstation subnet\nBILLING_CLIENT_CIDR=\"10.10.0.0/16\"     # Port operations LAN\n\n# \u2500\u2500 Pre-flight \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n[[ $EUID -ne 0 ]] && die \"Must be run as root.\"\ncommand -v firewall-cmd &>/dev/null || die \"firewalld not found: dnf install -y firewalld\"\ncommand -v semanage    &>/dev/null || die \"semanage not found: dnf install -y policycoreutils-python-utils\"\n\nsystemctl is-active --quiet firewalld || systemctl start firewalld\nok \"firewalld is running\"\n\ngetenforce | grep -qiE '^enforcing$' || {\n    warn \"SELinux not in enforcing mode \u2014 enabling...\"\n    setenforce 1\n    sed -i 's/^SELINUX=.*/SELINUX=enforcing/' /etc/selinux/config\n    ok \"SELinux set to enforcing (persistent)\"\n}\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PART 1 \u2014 FIREWALLD\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\nlog \"Configuring firewalld zones...\"\n\n# Create dedicated billing zone (idempotent)\nif ! firewall-cmd --permanent --get-zones | grep -qw \"$BILLING_ZONE\"; then\n    firewall-cmd --permanent --new-zone=\"$BILLING_ZONE\"\n    ok \"Zone created: $BILLING_ZONE\"\nelse\n    warn \"Zone '$BILLING_ZONE' already exists \u2014 reconfiguring\"\nfi\n\n# \u2500\u2500 Public Zone \u2014 minimal exposure \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nfirewall-cmd --permanent --zone=public --remove-service=ssh 2>/dev/null || true\nfirewall-cmd --permanent --zone=public --set-target=DROP\nok \"Public zone: target=DROP, SSH removed\"\n\n# \u2500\u2500 Billing Zone \u2014 web + custom SSH \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Allow HTTPS for billing portal\nfirewall-cmd --permanent --zone=\"$BILLING_ZONE\" --add-service=https\nfirewall-cmd --permanent --zone=\"$BILLING_ZONE\" --add-service=http\n\n# Custom SSH port in billing zone \u2014 restricted to admin subnet only\nfirewall-cmd --permanent --zone=\"$BILLING_ZONE\" \\\n    --add-rich-rule=\"rule family='ipv4' source address='${TRUSTED_ADMIN_CIDR}' port port='${SSH_PORT}' protocol='tcp' accept\"\nok \"Rich rule: SSH port $SSH_PORT allowed from $TRUSTED_ADMIN_CIDR\"\n\n# Allow billing client LAN to reach HTTP/HTTPS\nfirewall-cmd --permanent --zone=\"$BILLING_ZONE\" \\\n    --add-rich-rule=\"rule family='ipv4' source address='${BILLING_CLIENT_CIDR}' service name='https' accept\"\nok \"Rich rule: HTTPS allowed from billing LAN $BILLING_CLIENT_CIDR\"\n\n# Rate-limit new connections to prevent billing portal abuse\nfirewall-cmd --permanent --zone=\"$BILLING_ZONE\" \\\n    --add-rich-rule=\"rule family='ipv4' service name='http' limit value='100/m' accept\"\nok \"Rich rule: HTTP rate-limited to 100 connections/min\"\n\n# Reject (not drop) everything else for better diagnostics\nfirewall-cmd --permanent --zone=\"$BILLING_ZONE\" --set-target=REJECT\n\n# Apply all changes\nfirewall-cmd --reload\nok \"firewalld reloaded \u2014 all rules applied\"\n\n# \u2500\u2500 Assign Network Interfaces to Zones \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Detect primary interface (first non-loopback)\nPRIMARY_IF=$(ip -o link show | awk -F': ' '$2 != \"lo\" {print $2; exit}')\nif [[ -n \"$PRIMARY_IF\" ]]; then\n    firewall-cmd --permanent --zone=\"$BILLING_ZONE\" --add-interface=\"$PRIMARY_IF\" 2>/dev/null || \\\n        firewall-cmd --permanent --zone=\"$BILLING_ZONE\" --change-interface=\"$PRIMARY_IF\"\n    firewall-cmd --reload\n    ok \"Interface $PRIMARY_IF assigned to zone: $BILLING_ZONE\"\nfi\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PART 2 \u2014 SELINUX\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\nlog \"Configuring SELinux policies for port billing...\"\n\n# \u2500\u2500 Custom SSH Port Context \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif semanage port --list | grep -q \"^ssh_port_t.*${SSH_PORT}\"; then\n    warn \"SELinux: SSH port $SSH_PORT already labelled ssh_port_t\"\nelse\n    semanage port --add --type ssh_port_t --proto tcp \"$SSH_PORT\"\n    ok \"SELinux port context: $SSH_PORT/tcp \u2192 ssh_port_t\"\nfi\n\n# \u2500\u2500 Nginx / Application File Contexts \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndeclare -A FCONTEXTS=(\n    [\"/srv/portbill/data(/.*)?\"]=\"httpd_sys_content_t\"\n    [\"/srv/portbill/logs(/.*)?\"]=\"httpd_log_t\"\n    [\"/srv/portbill/backup(/.*)?\"]=\"var_t\"\n    [\"/etc/nginx/conf.d(/.*)?\"]=\"httpd_config_t\"\n)\n\nfor fpath in \"${!FCONTEXTS[@]}\"; do\n    ftype=\"${FCONTEXTS[$fpath]}\"\n    semanage fcontext --add --type \"$ftype\" \"$fpath\" 2>/dev/null || \\\n        semanage fcontext --modify --type \"$ftype\" \"$fpath\"\n    ok \"SELinux fcontext: $fpath \u2192 $ftype\"\ndone\n\nrestorecon -Rv /srv/portbill/ /etc/nginx/ 2>/dev/null || true\nok \"restorecon applied to /srv/portbill/ and /etc/nginx/\"\n\n# \u2500\u2500 SELinux Booleans \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ndeclare -A BOOLEANS=(\n    [httpd_can_network_connect]=\"on\"        # Nginx \u2192 Podman proxy\n    [httpd_read_user_content]=\"off\"         # Least privilege\n    [httpd_enable_homedirs]=\"off\"           # Least privilege\n    [httpd_use_nfs]=\"off\"                   # Not using NFS\n)\n\nfor bool_name in \"${!BOOLEANS[@]}\"; do\n    bool_val=\"${BOOLEANS[$bool_name]}\"\n    setsebool -P \"$bool_name\" \"$bool_val\"\n    ok \"SELinux boolean: $bool_name=$bool_val (persistent)\"\ndone\n\n# \u2500\u2500 Verification \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\necho -e \"\\n${BOLD}${CYAN}\u2500\u2500 Firewall Status \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500${RESET}\"\nfirewall-cmd --zone=\"$BILLING_ZONE\" --list-all\n\necho -e \"\\n${BOLD}${CYAN}\u2500\u2500 SELinux Status \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500${RESET}\"\nsestatus | head -5\nsemanage port --list | grep -E \"ssh_port_t.*${SSH_PORT}|^ssh_port_t\"\necho \"\"\nok \"Firewall & SELinux hardening complete.\"\n",

  "04_ssh_hardening.sh": "#!/usr/bin/env bash\n# Smart Port Billing Infrastructure \u2014 SSH Hardening\n# RHCSA Skills: SSH Configuration, Key-Based Authentication, Service Management\n# Run as root on RHEL 9\nset -euo pipefail\ntrap 'echo \"[ERROR] Line ${LINENO}: ${BASH_COMMAND}\" >&2; exit 1' ERR\n\nRED='\\033[0;31m'; GREEN='\\033[0;32m'; CYAN='\\033[0;36m'\nYELLOW='\\033[1;33m'; BOLD='\\033[1m'; RESET='\\033[0m'\n\nlog()  { echo -e \"${CYAN}[$(date '+%H:%M:%S')] INFO${RESET}  $*\"; }\nok()   { echo -e \"${GREEN}[$(date '+%H:%M:%S')]  OK  ${RESET}  $*\"; }\nwarn() { echo -e \"${YELLOW}[$(date '+%H:%M:%S')] WARN${RESET}  $*\"; }\ndie()  { echo -e \"${RED}[$(date '+%H:%M:%S')] FAIL${RESET}  $*\" >&2; exit 1; }\n\n# \u2500\u2500 Configuration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nSSH_PORT=2222\nSSHD_CONFIG=\"/etc/ssh/sshd_config\"\nSSHD_BACKUP=\"/etc/ssh/sshd_config.pre-hardening.$(date +%Y%m%d%H%M%S)\"\nALLOWED_GROUPS=\"billing-admin\"\nBANNER_FILE=\"/etc/ssh/billing-banner\"\n\n# \u2500\u2500 Pre-flight \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n[[ $EUID -ne 0 ]] && die \"Must be run as root.\"\n[[ -f \"$SSHD_CONFIG\" ]] || die \"sshd_config not found at $SSHD_CONFIG\"\n\n# Backup original config\ncp \"$SSHD_CONFIG\" \"$SSHD_BACKUP\"\nok \"Backup created: $SSHD_BACKUP\"\n\n# \u2500\u2500 Legal Warning Banner \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ncat > \"$BANNER_FILE\" <<'EOF'\n\u2554\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2557\n\u2551        SMART PORT BILLING INFRASTRUCTURE \u2014 AUTHORIZED ACCESS      \u2551\n\u2551                                                                    \u2551\n\u2551  This system is for AUTHORIZED PERSONNEL ONLY.                    \u2551\n\u2551  Unauthorized access or use is STRICTLY PROHIBITED and may be    \u2551\n\u2551  subject to civil and criminal penalties.                         \u2551\n\u2551  All activities on this system are monitored and recorded.        \u2551\n\u255a\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u255d\nEOF\nchmod 0644 \"$BANNER_FILE\"\nok \"Legal banner created: $BANNER_FILE\"\n\n# \u2500\u2500 Apply Hardened sshd_config \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlog \"Writing hardened SSH configuration...\"\n\n# Helper: set or replace a directive (case-insensitive key match)\nssh_set() {\n    local key=\"$1\" val=\"$2\"\n    if grep -qiE \"^#?[[:space:]]*${key}[[:space:]]\" \"$SSHD_CONFIG\"; then\n        sed -i -E \"s|^#?[[:space:]]*${key}[[:space:]].*|${key} ${val}|I\" \"$SSHD_CONFIG\"\n    else\n        echo \"${key} ${val}\" >> \"$SSHD_CONFIG\"\n    fi\n    log \"  $key \u2192 $val\"\n}\n\nssh_set \"Port\"                     \"$SSH_PORT\"\nssh_set \"AddressFamily\"            \"inet\"\nssh_set \"ListenAddress\"            \"0.0.0.0\"\n\n# Authentication hardening\nssh_set \"PermitRootLogin\"          \"no\"\nssh_set \"PubkeyAuthentication\"     \"yes\"\nssh_set \"PasswordAuthentication\"   \"no\"\nssh_set \"PermitEmptyPasswords\"     \"no\"\nssh_set \"ChallengeResponseAuthentication\" \"no\"\nssh_set \"KbdInteractiveAuthentication\"    \"no\"\nssh_set \"UsePAM\"                   \"yes\"\n\n# Restrict access to billing-admin group only\nssh_set \"AllowGroups\"              \"$ALLOWED_GROUPS\"\n\n# Connection hardening\nssh_set \"LoginGraceTime\"           \"30\"\nssh_set \"MaxAuthTries\"             \"3\"\nssh_set \"MaxSessions\"              \"5\"\nssh_set \"MaxStartups\"              \"5:30:10\"\nssh_set \"ClientAliveInterval\"      \"300\"\nssh_set \"ClientAliveCountMax\"      \"2\"\n\n# Disable unused features\nssh_set \"X11Forwarding\"            \"no\"\nssh_set \"AllowAgentForwarding\"     \"no\"\nssh_set \"AllowTcpForwarding\"       \"no\"\nssh_set \"PermitTunnel\"             \"no\"\nssh_set \"GatewayPorts\"             \"no\"\nssh_set \"PermitUserEnvironment\"    \"no\"\n\n# Logging\nssh_set \"LogLevel\"                 \"VERBOSE\"\nssh_set \"SyslogFacility\"           \"AUTHPRIV\"\n\n# Legal banner\nssh_set \"Banner\"                   \"$BANNER_FILE\"\n\n# Secure algorithms only (RHEL 9 crypto policy compliant)\nssh_set \"KexAlgorithms\"            \"curve25519-sha256,diffie-hellman-group14-sha256\"\nssh_set \"HostKeyAlgorithms\"        \"ssh-ed25519,rsa-sha2-512,rsa-sha2-256\"\nssh_set \"Ciphers\"                  \"chacha20-poly1305@openssh.com,aes256-gcm@openssh.com\"\nssh_set \"MACs\"                     \"hmac-sha2-512-etm@openssh.com,hmac-sha2-256-etm@openssh.com\"\n\nok \"Hardened configuration written.\"\n\n# \u2500\u2500 Validate Config Before Restart \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlog \"Validating sshd_config syntax...\"\nif ! sshd -t -f \"$SSHD_CONFIG\"; then\n    warn \"Config validation failed \u2014 restoring backup\"\n    cp \"$SSHD_BACKUP\" \"$SSHD_CONFIG\"\n    die \"Restored original config. Review errors above.\"\nfi\nok \"Configuration syntax valid.\"\n\n# \u2500\u2500 Authorized Keys Setup \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nADMIN_HOME=$(getent passwd portadmin | cut -d: -f6)\nSSH_DIR=\"$ADMIN_HOME/.ssh\"\nAUTH_KEYS=\"$SSH_DIR/authorized_keys\"\n\nmkdir -p \"$SSH_DIR\"\nchmod 0700 \"$SSH_DIR\"\nchown portadmin:billing-admin \"$SSH_DIR\"\n\nif [[ ! -f \"$AUTH_KEYS\" ]]; then\n    touch \"$AUTH_KEYS\"\n    chmod 0600 \"$AUTH_KEYS\"\n    chown portadmin:billing-admin \"$AUTH_KEYS\"\n    warn \"authorized_keys created but EMPTY \u2014 add public key before restarting sshd!\"\n    warn \"Command: echo '<your_pubkey>' >> $AUTH_KEYS\"\nelse\n    ok \"authorized_keys exists: $AUTH_KEYS\"\nfi\n\n# \u2500\u2500 Restart SSH Service \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlog \"Restarting sshd...\"\nsystemctl restart sshd\nsystemctl enable sshd\nok \"sshd restarted and enabled.\"\n\n# \u2500\u2500 Verify SELinux Port Context \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif command -v semanage &>/dev/null; then\n    if ! semanage port --list | grep -q \"ssh_port_t.*${SSH_PORT}\"; then\n        warn \"SELinux ssh_port_t not set for port $SSH_PORT \u2014 run 03_firewall_selinux.sh first\"\n    else\n        ok \"SELinux: port $SSH_PORT correctly labelled ssh_port_t\"\n    fi\nfi\n\n# \u2500\u2500 Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\necho -e \"\\n${BOLD}${CYAN}\u2500\u2500 SSH Hardening Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500${RESET}\"\necho -e \"  Listening port     : ${SSH_PORT}/tcp\"\necho -e \"  Root login         : DISABLED\"\necho -e \"  Password auth      : DISABLED (keys only)\"\necho -e \"  Allowed groups     : ${ALLOWED_GROUPS}\"\necho -e \"  Max auth tries     : 3\"\necho -e \"  Session timeout    : 300s idle (2 misses)\"\necho -e \"  Config backup      : ${SSHD_BACKUP}\"\necho -e \"  Authorized keys    : ${AUTH_KEYS}\"\necho \"\"\nss -tlnp | grep \":${SSH_PORT}\"\nok \"SSH hardening complete.\"\n",

  "05_service_deploy.sh": "#!/usr/bin/env bash\n# Smart Port Billing Infrastructure \u2014 Application Deployment\n# RHCSA Skills: Podman Container Management, Systemd Unit Files, Nginx Reverse Proxy\n# Run as root on RHEL 9\nset -euo pipefail\ntrap 'echo \"[ERROR] Line ${LINENO}: ${BASH_COMMAND}\" >&2; exit 1' ERR\n\nRED='\\033[0;31m'; GREEN='\\033[0;32m'; CYAN='\\033[0;36m'\nYELLOW='\\033[1;33m'; BOLD='\\033[1m'; RESET='\\033[0m'\n\nlog()  { echo -e \"${CYAN}[$(date '+%H:%M:%S')] INFO${RESET}  $*\"; }\nok()   { echo -e \"${GREEN}[$(date '+%H:%M:%S')]  OK  ${RESET}  $*\"; }\nwarn() { echo -e \"${YELLOW}[$(date '+%H:%M:%S')] WARN${RESET}  $*\"; }\ndie()  { echo -e \"${RED}[$(date '+%H:%M:%S')] FAIL${RESET}  $*\" >&2; exit 1; }\n\n# \u2500\u2500 Configuration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nAPP_NAME=\"portbill\"\nAPP_IMAGE=\"ghcr.io/samiulAsumel/portbill:latest\"\nAPP_PORT=3000\nNGINX_PORT=443\nNGINX_HTTP_PORT=80\nAPP_DATA_DIR=\"/srv/portbill/data\"\nAPP_LOGS_DIR=\"/srv/portbill/logs\"\nSYSTEMD_UNIT=\"/etc/systemd/system/${APP_NAME}.service\"\nNGINX_CONF=\"/etc/nginx/conf.d/${APP_NAME}.conf\"\n\n# \u2500\u2500 Pre-flight \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n[[ $EUID -ne 0 ]] && die \"Must be run as root.\"\ncommand -v podman &>/dev/null  || die \"Podman not found: dnf install -y podman\"\ncommand -v nginx  &>/dev/null  || die \"Nginx not found: dnf install -y nginx\"\n[[ -d \"$APP_DATA_DIR\" ]]       || die \"Data dir missing \u2014 run 02_storage_lvm.sh first\"\n\n# \u2500\u2500 Pull Container Image \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlog \"Pulling container image: $APP_IMAGE\"\npodman pull \"$APP_IMAGE\" || {\n    warn \"Image pull failed \u2014 using local image if available\"\n    podman image exists \"$APP_IMAGE\" || die \"No local image found for $APP_IMAGE\"\n}\nok \"Container image ready: $APP_IMAGE\"\n\n# \u2500\u2500 Create Systemd Unit for Podman Container \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlog \"Creating systemd unit: $SYSTEMD_UNIT\"\ncat > \"$SYSTEMD_UNIT\" <<EOF\n[Unit]\nDescription=Smart Port Billing Application (Podman)\nDocumentation=https://github.com/samiulAsumel/portbill\nAfter=network-online.target\nWants=network-online.target\nRequiresMountsFor=/srv/portbill\n\n[Service]\nType=simple\nRestart=on-failure\nRestartSec=10s\nTimeoutStartSec=60s\nTimeoutStopSec=30s\n\n# Security hardening\nNoNewPrivileges=yes\nPrivateTmp=yes\nProtectSystem=strict\nProtectHome=yes\nReadWritePaths=/srv/portbill/data /srv/portbill/logs\n\n# Container run\nExecStartPre=/usr/bin/podman stop --ignore ${APP_NAME} 2>/dev/null || true\nExecStartPre=/usr/bin/podman rm   --ignore ${APP_NAME} 2>/dev/null || true\nExecStart=/usr/bin/podman run \\\\\n    --name ${APP_NAME} \\\\\n    --publish 127.0.0.1:${APP_PORT}:${APP_PORT} \\\\\n    --volume ${APP_DATA_DIR}:/app/data:Z \\\\\n    --volume ${APP_LOGS_DIR}:/app/logs:Z \\\\\n    --env NODE_ENV=production \\\\\n    --env PORT=${APP_PORT} \\\\\n    --env LOG_DIR=/app/logs \\\\\n    --read-only \\\\\n    --security-opt no-new-privileges \\\\\n    --health-cmd='curl -f http://localhost:${APP_PORT}/health || exit 1' \\\\\n    --health-interval=30s \\\\\n    --health-retries=3 \\\\\n    ${APP_IMAGE}\n\nExecStop=/usr/bin/podman stop ${APP_NAME}\nExecStopPost=/usr/bin/podman rm --ignore ${APP_NAME}\n\n[Install]\nWantedBy=multi-user.target\nEOF\nchmod 0644 \"$SYSTEMD_UNIT\"\nok \"Systemd unit written: $SYSTEMD_UNIT\"\n\n# \u2500\u2500 Nginx TLS Reverse Proxy Configuration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# Self-signed cert for demonstration (replace with Let's Encrypt in production)\nSSL_DIR=\"/etc/nginx/ssl/portbill\"\nmkdir -p \"$SSL_DIR\"\nif [[ ! -f \"$SSL_DIR/server.crt\" ]]; then\n    openssl req -x509 -nodes -days 365 -newkey rsa:4096 \\\n        -keyout \"$SSL_DIR/server.key\" \\\n        -out    \"$SSL_DIR/server.crt\" \\\n        -subj \"/C=BD/ST=Chittagong/O=Port Authority/CN=portbill.local\" \\\n        -quiet\n    chmod 0600 \"$SSL_DIR/server.key\"\n    ok \"Self-signed TLS certificate generated: $SSL_DIR/\"\n    warn \"PRODUCTION: Replace with a CA-signed cert (Let's Encrypt recommended)\"\nfi\n\nlog \"Writing Nginx configuration: $NGINX_CONF\"\ncat > \"$NGINX_CONF\" <<EOF\n# Port Billing \u2014 Nginx TLS Reverse Proxy\nupstream portbill_backend {\n    server 127.0.0.1:${APP_PORT};\n    keepalive 32;\n}\n\nserver {\n    listen ${NGINX_HTTP_PORT};\n    server_name _;\n    return 301 https://\\$host\\$request_uri;\n}\n\nserver {\n    listen ${NGINX_PORT} ssl http2;\n    server_name portbill.local;\n\n    ssl_certificate     ${SSL_DIR}/server.crt;\n    ssl_certificate_key ${SSL_DIR}/server.key;\n    ssl_protocols       TLSv1.2 TLSv1.3;\n    ssl_ciphers         ECDHE-ECDSA-AES256-GCM-SHA384:ECDHE-RSA-AES256-GCM-SHA384;\n    ssl_prefer_server_ciphers on;\n    ssl_session_cache   shared:SSL:10m;\n    ssl_session_timeout 1d;\n\n    add_header Strict-Transport-Security \"max-age=63072000; includeSubDomains; preload\" always;\n    add_header X-Frame-Options            \"DENY\"           always;\n    add_header X-Content-Type-Options     \"nosniff\"        always;\n    add_header X-XSS-Protection           \"1; mode=block\"  always;\n    add_header Referrer-Policy            \"strict-origin\"  always;\n\n    access_log /var/log/nginx/portbill.access.log combined;\n    error_log  /var/log/nginx/portbill.error.log  warn;\n\n    location /health {\n        proxy_pass http://portbill_backend;\n        access_log off;\n    }\n\n    location / {\n        proxy_pass         http://portbill_backend;\n        proxy_http_version 1.1;\n        proxy_set_header   Upgrade           \\$http_upgrade;\n        proxy_set_header   Connection        \"upgrade\";\n        proxy_set_header   Host              \\$host;\n        proxy_set_header   X-Real-IP         \\$remote_addr;\n        proxy_set_header   X-Forwarded-For   \\$proxy_add_x_forwarded_for;\n        proxy_set_header   X-Forwarded-Proto \\$scheme;\n        proxy_read_timeout 60s;\n        proxy_send_timeout 60s;\n        client_max_body_size 10M;\n    }\n}\nEOF\nok \"Nginx configuration written: $NGINX_CONF\"\n\n# \u2500\u2500 SELinux: Allow Nginx to Proxy to App Port \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif command -v semanage &>/dev/null; then\n    semanage port --add --type http_port_t --proto tcp \"$APP_PORT\" 2>/dev/null || \\\n        warn \"SELinux: port $APP_PORT may already be labelled http_port_t\"\n    ok \"SELinux: port $APP_PORT \u2192 http_port_t\"\nfi\n\n# \u2500\u2500 Validate and Start Services \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nnginx -t || die \"Nginx config syntax error \u2014 fix $NGINX_CONF before starting\"\nok \"Nginx configuration syntax valid.\"\n\nsystemctl daemon-reload\nsystemctl enable --now nginx\nok \"Nginx enabled and started.\"\n\nsystemctl enable --now \"$APP_NAME\"\nok \"portbill service enabled and started.\"\n\n# \u2500\u2500 Health Check \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlog \"Waiting for application health check (max 60s)...\"\nfor i in $(seq 1 12); do\n    if curl -sf --max-time 5 \"http://127.0.0.1:${APP_PORT}/health\" &>/dev/null; then\n        ok \"Health check passed on attempt $i\"\n        break\n    fi\n    sleep 5\n    [[ $i -eq 12 ]] && warn \"Health check did not pass \u2014 check: journalctl -u ${APP_NAME}\"\ndone\n\n# \u2500\u2500 Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\necho -e \"\\n${BOLD}${CYAN}\u2500\u2500 Deployment Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500${RESET}\"\nsystemctl --no-pager status \"$APP_NAME\" nginx | grep -E \"Active:|Loaded:\"\necho \"\"\necho -e \"  App container    : ${APP_NAME} \u2192 127.0.0.1:${APP_PORT}\"\necho -e \"  Nginx proxy      : :${NGINX_HTTP_PORT} \u2192 :${NGINX_PORT} (TLS)\"\necho -e \"  Data volume      : ${APP_DATA_DIR}\"\necho -e \"  Logs             : ${APP_LOGS_DIR}\"\necho -e \"  Systemd unit     : ${SYSTEMD_UNIT}\"\necho \"\"\nok \"Deployment complete.\"\n",

  "06_acl_backup.sh": "#!/usr/bin/env bash\n# Smart Port Billing Infrastructure \u2014 ACL Configuration & Automated Backup\n# RHCSA Skills: POSIX ACLs, setfacl/getfacl, Cron/Systemd Timer, Backup Integrity\n# Run as root on RHEL 9\nset -euo pipefail\ntrap 'echo \"[ERROR] Line ${LINENO}: ${BASH_COMMAND}\" >&2; exit 1' ERR\n\nRED='\\033[0;31m'; GREEN='\\033[0;32m'; CYAN='\\033[0;36m'\nYELLOW='\\033[1;33m'; BOLD='\\033[1m'; RESET='\\033[0m'\n\nlog()  { echo -e \"${CYAN}[$(date '+%H:%M:%S')] INFO${RESET}  $*\"; }\nok()   { echo -e \"${GREEN}[$(date '+%H:%M:%S')]  OK  ${RESET}  $*\"; }\nwarn() { echo -e \"${YELLOW}[$(date '+%H:%M:%S')] WARN${RESET}  $*\"; }\ndie()  { echo -e \"${RED}[$(date '+%H:%M:%S')] FAIL${RESET}  $*\" >&2; exit 1; }\n\n# \u2500\u2500 Configuration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nDATA_DIR=\"/srv/portbill/data\"\nLOGS_DIR=\"/srv/portbill/logs\"\nBACKUP_DIR=\"/srv/portbill/backup\"\nBACKUP_SCRIPT=\"/usr/local/bin/portbill-backup\"\nBACKUP_RETENTION_DAYS=30\nSYSTEMD_TIMER_DIR=\"/etc/systemd/system\"\n\n# \u2500\u2500 Pre-flight \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n[[ $EUID -ne 0 ]] && die \"Must be run as root.\"\ncommand -v setfacl &>/dev/null || die \"acl tools not found: dnf install -y acl\"\nfor d in \"$DATA_DIR\" \"$LOGS_DIR\" \"$BACKUP_DIR\"; do\n    [[ -d \"$d\" ]] || die \"Directory missing: $d \u2014 run 02_storage_lvm.sh first\"\ndone\n\n# \u2500\u2500 Verify ACL Support on Filesystem \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nif ! tune2fs -l \"$(findmnt -n -o SOURCE \"$DATA_DIR\")\" 2>/dev/null | grep -q \"acl\" &&\n   ! findmnt -n -o OPTIONS \"$DATA_DIR\" | grep -qE \"acl|xfs\"; then\n    warn \"Confirm XFS filesystem supports ACLs (XFS enables ACLs by default)\"\nfi\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PART 1 \u2014 ACL CONFIGURATION\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\nlog \"Configuring POSIX ACLs for billing data directories...\"\n\n# \u2500\u2500 /srv/portbill/data \u2014 Billing Transaction Records \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n# billing-admin: full control\n# billing-ops:   read + write (no execute on files)\n# port-ops:      read-only\n# billing-readonly: read-only\n# auditor users: read-only + no delete\n\nsetfacl --recursive --modify \\\n    \"g:billing-admin:rwx,g:billing-ops:rwx,g:port-ops:r-x,g:billing-readonly:r-x\" \\\n    \"$DATA_DIR\"\n\n# Default ACLs \u2014 inherited by new files and subdirectories\nsetfacl --recursive --modify \"d:g:billing-admin:rwx\" \"$DATA_DIR\"\nsetfacl --recursive --modify \"d:g:billing-ops:rw-\"  \"$DATA_DIR\"\nsetfacl --recursive --modify \"d:g:port-ops:r--\"     \"$DATA_DIR\"\nsetfacl --recursive --modify \"d:g:billing-readonly:r--\" \"$DATA_DIR\"\nsetfacl --recursive --modify \"d:o::---\"              \"$DATA_DIR\"\nok \"ACLs set on: $DATA_DIR\"\n\n# \u2500\u2500 /srv/portbill/logs \u2014 Application & Audit Logs \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nsetfacl --recursive --modify \\\n    \"g:billing-admin:rwx,g:billing-ops:r-x,g:billing-readonly:r-x\" \\\n    \"$LOGS_DIR\"\nsetfacl --recursive --modify \"d:g:billing-admin:rwx\" \"$LOGS_DIR\"\nsetfacl --recursive --modify \"d:g:billing-ops:r--\"   \"$LOGS_DIR\"\nsetfacl --recursive --modify \"d:g:billing-readonly:r--\" \"$LOGS_DIR\"\nsetfacl --recursive --modify \"d:o::---\"               \"$LOGS_DIR\"\nok \"ACLs set on: $LOGS_DIR\"\n\n# \u2500\u2500 /srv/portbill/backup \u2014 Backup Target \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nsetfacl --recursive --modify \"g:billing-admin:rwx\" \"$BACKUP_DIR\"\nsetfacl --recursive --modify \"d:g:billing-admin:rwx\" \"$BACKUP_DIR\"\nsetfacl --recursive --modify \"d:o::---\" \"$BACKUP_DIR\"\nok \"ACLs set on: $BACKUP_DIR\"\n\n# \u2500\u2500 Report Applied ACLs \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\necho -e \"\\n${BOLD}ACL Report \u2014 ${DATA_DIR}${RESET}\"\ngetfacl --skip-base \"$DATA_DIR\" 2>/dev/null | head -20\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PART 2 \u2014 AUTOMATED BACKUP SCRIPT\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\nlog \"Creating backup script: $BACKUP_SCRIPT\"\ncat > \"$BACKUP_SCRIPT\" <<'BACKUP_SCRIPT_EOF'\n#!/usr/bin/env bash\n# portbill-backup \u2014 Automated backup for Port Billing Infrastructure\nset -euo pipefail\ntrap 'echo \"[BACKUP ERROR] Line ${LINENO}: ${BASH_COMMAND}\" >> /var/log/portbill-backup.log' ERR\n\nLOG_FILE=\"/var/log/portbill-backup.log\"\nDATA_DIR=\"/srv/portbill/data\"\nLOGS_DIR=\"/srv/portbill/logs\"\nBACKUP_DIR=\"/srv/portbill/backup\"\nTIMESTAMP=$(date '+%Y%m%d_%H%M%S')\nARCHIVE_NAME=\"portbill_backup_${TIMESTAMP}.tar.gz\"\nARCHIVE_PATH=\"${BACKUP_DIR}/${ARCHIVE_NAME}\"\nCHECKSUM_FILE=\"${ARCHIVE_PATH}.sha256\"\nRETENTION_DAYS=30\n\nexec >> \"$LOG_FILE\" 2>&1\necho \"=== Backup started: $(date) ===\"\n\n# Create compressed archive with ACL preservation\ntar \\\n    --create \\\n    --gzip \\\n    --file=\"$ARCHIVE_PATH\" \\\n    --acls \\\n    --selinux \\\n    --preserve-permissions \\\n    --one-file-system \\\n    --exclude=\"*.tmp\" \\\n    --exclude=\"*.lock\" \\\n    \"$DATA_DIR\" \"$LOGS_DIR\"\n\n# SHA-256 integrity checksum\nsha256sum \"$ARCHIVE_PATH\" > \"$CHECKSUM_FILE\"\necho \"Checksum: $(cat \"$CHECKSUM_FILE\")\"\n\n# Verify archive integrity\ntar --list --gzip --file=\"$ARCHIVE_PATH\" > /dev/null\necho \"Archive verified: $ARCHIVE_PATH\"\necho \"Size: $(du -sh \"$ARCHIVE_PATH\" | cut -f1)\"\n\n# Retention: remove backups older than RETENTION_DAYS\nfind \"$BACKUP_DIR\" -name \"portbill_backup_*.tar.gz\" \\\n    -mtime +\"$RETENTION_DAYS\" -delete -print | \\\n    while read -r old; do\n        echo \"Purged old backup: $old\"\n        rm -f \"${old}.sha256\"\n    done\n\n# Log backup inventory\nBACKUP_COUNT=$(find \"$BACKUP_DIR\" -name \"portbill_backup_*.tar.gz\" | wc -l)\nBACKUP_TOTAL=$(du -sh \"$BACKUP_DIR\" | cut -f1)\necho \"Backup count: $BACKUP_COUNT | Total size: $BACKUP_TOTAL\"\necho \"=== Backup complete: $(date) ===\"\nBACKUP_SCRIPT_EOF\n\nchmod 0750 \"$BACKUP_SCRIPT\"\nchown root:billing-admin \"$BACKUP_SCRIPT\"\nok \"Backup script created: $BACKUP_SCRIPT\"\n\n# \u2500\u2500 Systemd Timer (preferred over cron for RHEL 9) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ncat > \"${SYSTEMD_TIMER_DIR}/portbill-backup.service\" <<EOF\n[Unit]\nDescription=Port Billing Automated Backup\nAfter=portbill.service\n\n[Service]\nType=oneshot\nExecStart=${BACKUP_SCRIPT}\nUser=root\nStandardOutput=journal\nStandardError=journal\nEOF\n\ncat > \"${SYSTEMD_TIMER_DIR}/portbill-backup.timer\" <<EOF\n[Unit]\nDescription=Port Billing Backup Timer \u2014 Daily at 02:00\n\n[Timer]\nOnCalendar=*-*-* 02:00:00\nPersistent=true\nRandomizedDelaySec=300\n\n[Install]\nWantedBy=timers.target\nEOF\n\nsystemctl daemon-reload\nsystemctl enable --now portbill-backup.timer\nok \"Systemd timer enabled: portbill-backup.timer (daily at 02:00)\"\n\n# \u2500\u2500 Test Backup (dry run) \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nlog \"Running test backup...\"\nTEST_ARCHIVE=\"${BACKUP_DIR}/portbill_backup_TEST.tar.gz\"\ntar --create --gzip --file=\"$TEST_ARCHIVE\" \\\n    --acls --selinux --one-file-system \\\n    \"$DATA_DIR\" 2>/dev/null && \\\n    rm -f \"$TEST_ARCHIVE\" && ok \"Test backup successful.\" || \\\n    warn \"Test backup failed \u2014 check permissions and storage\"\n\n# \u2500\u2500 Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\necho -e \"\\n${BOLD}${CYAN}\u2500\u2500 ACL & Backup Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500${RESET}\"\necho -e \"  Data ACLs        : billing-admin(rwx) billing-ops(rwx) port-ops(r-x) readonly(r-x)\"\necho -e \"  Log ACLs         : billing-admin(rwx) billing-ops(r-x) readonly(r-x)\"\necho -e \"  Backup script    : ${BACKUP_SCRIPT}\"\necho -e \"  Backup schedule  : Daily 02:00 (\u00b1 5min jitter)\"\necho -e \"  Retention        : ${BACKUP_RETENTION_DAYS} days\"\necho -e \"  Backup target    : ${BACKUP_DIR}\"\necho \"\"\nsystemctl --no-pager status portbill-backup.timer\nok \"ACL & backup configuration complete.\"\n",

  "07_log_monitor.sh": "#!/usr/bin/env bash\n# Smart Port Billing Infrastructure \u2014 Log Monitoring & Alerting\n# RHCSA Skills: journalctl, rsyslog, logrotate, Systemd Journal Filtering\n# Run as root on RHEL 9\nset -euo pipefail\ntrap 'echo \"[ERROR] Line ${LINENO}: ${BASH_COMMAND}\" >&2; exit 1' ERR\n\nRED='\\033[0;31m'; GREEN='\\033[0;32m'; CYAN='\\033[0;36m'\nYELLOW='\\033[1;33m'; BOLD='\\033[1m'; RESET='\\033[0m'\n\nlog()  { echo -e \"${CYAN}[$(date '+%H:%M:%S')] INFO${RESET}  $*\"; }\nok()   { echo -e \"${GREEN}[$(date '+%H:%M:%S')]  OK  ${RESET}  $*\"; }\nwarn() { echo -e \"${YELLOW}[$(date '+%H:%M:%S')] WARN${RESET}  $*\"; }\ndie()  { echo -e \"${RED}[$(date '+%H:%M:%S')] FAIL${RESET}  $*\" >&2; exit 1; }\n\n# \u2500\u2500 Configuration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nAPP_NAME=\"portbill\"\nALERT_EMAIL=\"portadmin@portbill.local\"     # Replace with real admin email\nLOG_DIR=\"/srv/portbill/logs\"\nAPP_LOG=\"${LOG_DIR}/app.log\"\nERROR_LOG=\"${LOG_DIR}/error.log\"\nAUDIT_LOG=\"${LOG_DIR}/billing-audit.log\"\nMONITOR_SCRIPT=\"/usr/local/bin/portbill-logmonitor\"\nLOGROTATE_CONF=\"/etc/logrotate.d/${APP_NAME}\"\nRSYSLOG_CONF=\"/etc/rsyslog.d/10-${APP_NAME}.conf\"\n\n# \u2500\u2500 Pre-flight \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n[[ $EUID -ne 0 ]] && die \"Must be run as root.\"\n[[ -d \"$LOG_DIR\" ]] || die \"Log directory missing \u2014 run 02_storage_lvm.sh first\"\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PART 1 \u2014 RSYSLOG: Route portbill logs to dedicated files\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\nlog \"Configuring rsyslog for $APP_NAME...\"\ncat > \"$RSYSLOG_CONF\" <<EOF\n# Port Billing \u2014 rsyslog routing rules\n# Capture all portbill container/service messages to dedicated log files\n\n\\$template PortbillFormat,\"%TIMESTAMP% %HOSTNAME% %syslogseverity-text% %msg%\\\\n\"\n\n# Match journal messages from portbill service\nif \\$programname == '${APP_NAME}' then {\n    action(type=\"omfile\" file=\"${APP_LOG}\"    template=\"PortbillFormat\")\n    action(type=\"omfile\" file=\"${AUDIT_LOG}\"  template=\"PortbillFormat\"\n           filterConditions=\"if \\$msg contains 'BILLING' or \\$msg contains 'PAYMENT' or \\$msg contains 'INVOICE'\")\n    stop\n}\n\n# Route nginx portbill access/error to app logs\nif \\$programname == 'nginx' and \\$msg contains 'portbill' then {\n    action(type=\"omfile\" file=\"${APP_LOG}\" template=\"PortbillFormat\")\n    stop\n}\n\n# SELinux AVC denials \u2014 separate file for security review\nif \\$programname == 'audit' and \\$msg contains 'avc' then {\n    action(type=\"omfile\" file=\"/var/log/portbill-avc.log\" template=\"PortbillFormat\")\n}\nEOF\nchmod 0644 \"$RSYSLOG_CONF\"\n\n# Validate rsyslog config before restart\nrsyslogd -N1 -f \"$RSYSLOG_CONF\" 2>&1 | grep -v \"^$\" || warn \"rsyslog validation warnings above\"\nsystemctl restart rsyslog\nok \"rsyslog configured: $RSYSLOG_CONF\"\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PART 2 \u2014 LOGROTATE: Manage log file size and retention\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\nlog \"Configuring logrotate for $APP_NAME...\"\ncat > \"$LOGROTATE_CONF\" <<EOF\n# Port Billing \u2014 logrotate configuration\n${LOG_DIR}/*.log {\n    daily\n    rotate 90\n    size 100M\n    compress\n    delaycompress\n    missingok\n    notifempty\n    copytruncate\n    dateext\n    dateformat -%Y%m%d\n    create 0640 root billing-ops\n    sharedscripts\n    postrotate\n        # Reload rsyslog to pick up rotated file handles\n        /usr/bin/systemctl reload rsyslog > /dev/null 2>&1 || true\n        # Signal portbill to reopen log file descriptors\n        /usr/bin/systemctl reload ${APP_NAME} > /dev/null 2>&1 || true\n    endscript\n}\n\n/var/log/nginx/portbill.*.log {\n    daily\n    rotate 30\n    compress\n    delaycompress\n    missingok\n    notifempty\n    postrotate\n        /usr/bin/systemctl reload nginx > /dev/null 2>&1 || true\n    endscript\n}\nEOF\nchmod 0644 \"$LOGROTATE_CONF\"\n\n# Test logrotate config\nlogrotate --debug \"$LOGROTATE_CONF\" 2>&1 | tail -10\nok \"logrotate configured: $LOGROTATE_CONF\"\n\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n# PART 3 \u2014 LOG MONITOR SCRIPT: Watch for critical billing events\n# \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\nlog \"Creating log monitor: $MONITOR_SCRIPT\"\ncat > \"$MONITOR_SCRIPT\" <<'MONITOR_EOF'\n#!/usr/bin/env bash\n# portbill-logmonitor \u2014 Real-time billing log monitor with alerting\nset -euo pipefail\n\nAPP_NAME=\"portbill\"\nLOG_FILE=\"/srv/portbill/logs/app.log\"\nAUDIT_LOG=\"/srv/portbill/logs/billing-audit.log\"\nALERT_EMAIL=\"${ALERT_EMAIL:-portadmin@portbill.local}\"\nALERT_LOG=\"/var/log/portbill-alerts.log\"\nSUMMARY_LOG=\"/var/log/portbill-daily-summary.log\"\n\n# Alert patterns with severity and message\ndeclare -A ALERT_PATTERNS=(\n    [\"CRITICAL:database connection\"]=\"CRIT: Database connectivity failure\"\n    [\"ERROR:payment processing\"]=\"ERR: Payment processor error\"\n    [\"ERROR:authentication\"]=\"ERR: Authentication system failure\"\n    [\"WARN:disk\"]=\"WARN: Disk space warning from app\"\n    [\"FATAL\"]=\"CRIT: Application fatal error\"\n    [\"OOM\"]=\"CRIT: Out-of-memory condition\"\n    [\"AUDIT:unauthorized\"]=\"SEC: Unauthorized billing access attempt\"\n    [\"AUDIT:privilege_escalation\"]=\"SEC: Privilege escalation detected\"\n)\n\nsend_alert() {\n    local severity=\"$1\" message=\"$2\"\n    local timestamp; timestamp=$(date '+%Y-%m-%d %H:%M:%S')\n    echo \"[$timestamp] [$severity] $message\" >> \"$ALERT_LOG\"\n\n    # Send email alert (requires mail/sendmail configured)\n    if command -v mail &>/dev/null; then\n        echo \"$message\" | mail -s \"[PORTBILL $severity] Alert - $(hostname)\" \"$ALERT_EMAIL\" 2>/dev/null || true\n    fi\n\n    # Log to systemd journal with priority\n    case \"$severity\" in\n        CRIT) logger -p user.crit  -t portbill-monitor \"$message\" ;;\n        ERR)  logger -p user.err   -t portbill-monitor \"$message\" ;;\n        SEC)  logger -p authpriv.crit -t portbill-monitor \"$message\" ;;\n        WARN) logger -p user.warning -t portbill-monitor \"$message\" ;;\n    esac\n}\n\ngenerate_daily_summary() {\n    local date_str; date_str=$(date '+%Y-%m-%d')\n    local summary_file=\"${SUMMARY_LOG%.log}_${date_str}.log\"\n\n    {\n        echo \"=== Port Billing Daily Log Summary: $date_str ===\"\n        echo \"\"\n        echo \"--- Service Status ---\"\n        systemctl --no-pager status portbill nginx 2>/dev/null | grep -E \"Active:|Main PID:\" || true\n        echo \"\"\n        echo \"--- Journal Error Count (last 24h) ---\"\n        journalctl -u portbill --since \"24 hours ago\" --no-pager -p err 2>/dev/null | wc -l\n        echo \"\"\n        echo \"--- Billing Audit Events ---\"\n        grep \"$(date '+%Y-%m-%d')\" \"$AUDIT_LOG\" 2>/dev/null | wc -l\n        echo \"\"\n        echo \"--- Login Events ---\"\n        journalctl --since \"24 hours ago\" --no-pager -t sshd 2>/dev/null | grep -c \"Accepted\" || echo \"0\"\n        echo \"\"\n        echo \"--- Disk Usage ---\"\n        df -h /srv/portbill/data /srv/portbill/logs /srv/portbill/backup 2>/dev/null\n        echo \"\"\n        echo \"=== End of Summary ===\"\n    } > \"$summary_file\"\n    cat \"$summary_file\"\n}\n\n# \u2500\u2500 Main: choose mode from argument \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ncase \"${1:-watch}\" in\n    watch)\n        # Tail journals for portbill service \u2014 real-time monitoring\n        echo \"[$(date)] Starting real-time log monitor for ${APP_NAME}...\"\n        journalctl -u \"$APP_NAME\" -f --no-pager --output=short-iso 2>/dev/null | \\\n        while IFS= read -r line; do\n            for pattern in \"${!ALERT_PATTERNS[@]}\"; do\n                IFS=':' read -r severity keyword <<< \"$pattern\"\n                if echo \"$line\" | grep -qi \"$keyword\"; then\n                    send_alert \"$severity\" \"${ALERT_PATTERNS[$pattern]}: $line\"\n                fi\n            done\n        done\n        ;;\n    summary)\n        generate_daily_summary\n        ;;\n    check)\n        # Quick health check \u2014 exit 1 if critical errors in last hour\n        error_count=$(journalctl -u \"$APP_NAME\" --since \"1 hour ago\" \\\n            --no-pager -p err 2>/dev/null | grep -c \"ERROR\\|FATAL\\|CRIT\" || true)\n        echo \"Errors in last 1h: $error_count\"\n        [[ $error_count -lt 10 ]] || { echo \"CRITICAL: High error rate\"; exit 1; }\n        ;;\n    *)\n        echo \"Usage: $0 [watch|summary|check]\"\n        exit 1\n        ;;\nesac\nMONITOR_EOF\n\nchmod 0750 \"$MONITOR_SCRIPT\"\nchown root:billing-admin \"$MONITOR_SCRIPT\"\nok \"Log monitor script: $MONITOR_SCRIPT\"\n\n# \u2500\u2500 Systemd Service for Continuous Log Monitoring \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\ncat > \"/etc/systemd/system/portbill-logmonitor.service\" <<EOF\n[Unit]\nDescription=Port Billing Log Monitor\nAfter=portbill.service rsyslog.service\nBindsTo=portbill.service\n\n[Service]\nType=simple\nExecStart=${MONITOR_SCRIPT} watch\nRestart=always\nRestartSec=5s\nStandardOutput=journal\nStandardError=journal\nSyslogIdentifier=portbill-monitor\n\n[Install]\nWantedBy=multi-user.target\nEOF\n\n# Systemd timer for daily summary\ncat > \"/etc/systemd/system/portbill-summary.timer\" <<EOF\n[Unit]\nDescription=Port Billing Daily Log Summary\n\n[Timer]\nOnCalendar=*-*-* 07:00:00\nPersistent=true\n\n[Install]\nWantedBy=timers.target\nEOF\n\ncat > \"/etc/systemd/system/portbill-summary.service\" <<EOF\n[Unit]\nDescription=Port Billing Daily Log Summary\n\n[Service]\nType=oneshot\nExecStart=${MONITOR_SCRIPT} summary\nStandardOutput=journal\nEOF\n\nsystemctl daemon-reload\nsystemctl enable --now portbill-logmonitor\nsystemctl enable --now portbill-summary.timer\nok \"Log monitor service and daily summary timer enabled.\"\n\n# \u2500\u2500 Journal Persistence Configuration \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nmkdir -p /var/log/journal\nsystemd-tmpfiles --create --prefix /var/log/journal\njournalctl --verify 2>/dev/null || warn \"Journal verify returned warnings \u2014 may be normal\"\nok \"Systemd journal set to persistent storage\"\n\n# \u2500\u2500 Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\necho -e \"\\n${BOLD}${CYAN}\u2500\u2500 Log Monitoring Summary \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500${RESET}\"\necho -e \"  rsyslog config   : $RSYSLOG_CONF\"\necho -e \"  logrotate config : $LOGROTATE_CONF\"\necho -e \"  Monitor script   : $MONITOR_SCRIPT\"\necho -e \"  Alert log        : /var/log/portbill-alerts.log\"\necho -e \"  AVC log          : /var/log/portbill-avc.log\"\necho -e \"  Daily summary    : /var/log/portbill-daily-summary_*.log\"\necho -e \"  Log retention    : 90 days (100MB rotate threshold)\"\necho -e \"  Alert email      : $ALERT_EMAIL\"\necho \"\"\necho -e \"  ${BOLD}Useful commands:${RESET}\"\necho -e \"  journalctl -u portbill -f                   # Follow app logs\"\necho -e \"  journalctl -u portbill -p err --since today  # Today's errors\"\necho -e \"  $MONITOR_SCRIPT summary                      # Daily report\"\necho -e \"  $MONITOR_SCRIPT check                        # Health check (CI/cron)\"\necho \"\"\nok \"Log monitoring setup complete.\"\n",

};
